// Load known holders from static data before making the RPC call
const staticData = $getWorkflowStaticData('global');
if (!staticData.knownHolders) {
  staticData.knownHolders = {};
}
// Pass the known holders count downstream for logging
return [{ json: { knownHolderCount: Object.keys(staticData.knownHolders).length, ready: true } }];

// Compare current top holder list with stored list to find NEW holders
// Uses Solana RPC getTokenLargestAccounts which returns top 20 accounts

const responseData = $input.first().json;

// RPC response format: { result: { value: [ { address, amount, decimals, uiAmount, uiAmountString } ] } }
const accounts = responseData?.result?.value || [];

if (accounts.length === 0) {
  return [{ json: { newHolders: [], totalHolders: 0, checkTimestamp: new Date().toISOString(), hasNewHolders: false, error: 'No accounts returned from RPC' } }];
}

// Build current holder map: { tokenAccountAddress -> uiAmount }
// Note: getTokenLargestAccounts returns token account addresses (not wallet addresses)
// We use them as unique identifiers for tracking purposes
const currentHolders = {};
for (const acct of accounts) {
  const address = acct.address || '';
  const balance = acct.uiAmount || parseFloat(acct.uiAmountString || '0');
  if (address && balance > 0) {
    currentHolders[address] = balance;
  }
}

// Retrieve previously stored holder list from Static Data
const staticData = $getWorkflowStaticData('global');
if (!staticData.knownHolders) {
  staticData.knownHolders = {};
}

const knownHolders = staticData.knownHolders;
const newHolders = [];

// Find accounts in currentHolders not in knownHolders
for (const [address, balance] of Object.entries(currentHolders)) {
  if (!knownHolders[address]) {
    const shortAddr = address.length > 8
      ? address.slice(0, 4) + '...' + address.slice(-4)
      : address;
    newHolders.push({
      wallet: address,
      balance,
      shortAddr
    });
  }
}

// Update stored holder list with all current holders
Object.assign(staticData.knownHolders, currentHolders);

const totalHolders = Object.keys(currentHolders).length;
const checkTimestamp = new Date().toISOString();

if (newHolders.length === 0) {
  return [{ json: { newHolders: [], totalHolders, checkTimestamp, hasNewHolders: false } }];
}

// Return one item per new holder for individual Telegram messages
return newHolders.map(h => ({
  json: {
    ...h,
    totalHolders,
    checkTimestamp,
    hasNewHolders: true,
    allNewHolders: newHolders
  }
}));

// Format welcome message for each new holder
const d = $input.first().json;
const balanceFormatted = new Intl.NumberFormat('en-US').format(Math.round(d.balance));
const solscanUrl = `https://solscan.io/account/${d.wallet}`;

return [{
  json: {
    ...d,
    telegramMessage: `👋 NEW YAKK HOLDER!\n\n🏠 Account: \`${d.shortAddr}\`\n💰 Balance: ${balanceFormatted} $YST\n🎉 Welcome to the YAKK den!\n\n👥 Top Holders Tracked: ${d.totalHolders}\n🔍 [View on Solscan](${solscanUrl})\n\n$YST #YakkStudios #Solana`
  }
}];
